// src/components/TelaEsterilizacao.jsx
import React, { useState, useEffect, useRef, useCallback } from 'react'
import axios from 'axios'
import { toast } from 'react-toastify'
import { Calendar, QrCode, Trash2 } from 'lucide-react'
import DatePicker from 'react-datepicker'
import { subDays } from 'date-fns'
import Etiqueta from './Etiqueta'
import { QRCodeSVG as QRCode } from 'qrcode.react'

export default function TelaEsterilizacao() {
  // Wizard steps: 1=escolher, 2=PIN, 3=histórico, 4=seleção, 5=impressão
  const [step, setStep] = useState(1)
  const [tipoOp, setTipoOp] = useState('') // 'entrada' ou 'saida'

  // Estados originais
  const [codigo, setCodigo] = useState('')
  const [allCaixas, setAllCaixas] = useState([])
  const [caixas, setCaixas] = useState([])
  const [alunoPin, setAlunoPin] = useState('')
  const [alunoNome, setAlunoNome] = useState('')
  const [pinValidated, setPinValidated] = useState(false)
  const [historico, setHistorico] = useState([])
  const [searchTerm, setSearchTerm] = useState('')
  const [filterDate, setFilterDate] = useState('')
  const [printAfter, setPrintAfter] = useState(false)
  const [printData, setPrintData] = useState(null)

  const componentRef = useRef(null)
  const datePickerRef = useRef(null)

  const storedUser = JSON.parse(localStorage.getItem('user') || '{}')
  const usuarioLogadoNome = storedUser.nome || ''

  const BADGE_STYLES = [
    'bg-blue-100 text-blue-800',
    'bg-green-100 text-green-800',
    'bg-yellow-100 text-yellow-800',
    'bg-purple-100 text-purple-800',
  ]

  // Imprime etiqueta em janela separada
  useEffect(() => {
    if (!printData) return
    const area = document.getElementById('area-impressao')
    if (!area) return
    const html = `
      <html>
        <head>
          <title>Impressão de Etiqueta</title>
          <style>body{margin:0;padding:8mm;font-family:sans-serif}</style>
        </head>
        <body>${area.innerHTML}</body>
      </html>`
    const printWindow = window.open('', '_blank', 'width=600,height=400')
    printWindow.document.write(html)
    printWindow.document.close()
    printWindow.focus()
    printWindow.print()
    setPrintData(null)
    setTimeout(() => printWindow.close(), 500)
  }, [printData])

  // Carrega caixas para autocomplete
  useEffect(() => {
    axios.get('/api/caixas')
      .then(res => setAllCaixas(res.data))
      .catch(() => setAllCaixas([]))
  }, [])

  // Busca histórico de movimentações
  const fetchHistory = useCallback(() => {
    if (!pinValidated || !alunoNome) return
    axios.get('/api/movimentacoes')
      .then(res => {
        const hoje = new Date()
        const from = subDays(hoje, 30).toISOString().slice(0, 10)
        const to = hoje.toISOString().slice(0, 10)
        const fil = res.data.filter(m => {
          const mesmoAluno = m.alunoNome === alunoNome
          const dia = new Date(m.criado_em).toISOString().slice(0, 10)
          return mesmoAluno && dia >= from && dia <= to
        })
        setHistorico(fil)
      })
      .catch(() => setHistorico([]))
  }, [alunoNome, pinValidated])

  useEffect(() => {
    fetchHistory()
  }, [fetchHistory])

  // Sugestões de caixas
  const suggestions = codigo
    ? allCaixas.filter(c =>
        c.nome.toLowerCase().includes(codigo.toLowerCase()) ||
        c.codigo_barras.includes(codigo)
      ).slice(0, 5)
    : []

  // Agrupa caixas para exibir nome+quantidade
  const caixaCounts = caixas.reduce((acc, c) => {
    if (!acc[c.id]) acc[c.id] = { ...c, qty: 1 }
    else acc[c.id].qty++
    return acc
  }, {})
  const uniqueCaixas = Object.values(caixaCounts)

  // Calcula estoque atual por caixa
  const stockByBox = {}
  historico.forEach(m => {
    stockByBox[m.caixaNome] = (stockByBox[m.caixaNome] || 0) + (m.tipo === 'entrada' ? 1 : -1)
  })

  // Reseta todo o wizard
  const resetWizard = () => {
    setStep(1)
    setTipoOp('')
    setAlunoPin('')
    setAlunoNome('')
    setPinValidated(false)
    setHistorico([])
    setSearchTerm('')
    setFilterDate('')
    setCodigo('')
    setCaixas([])
    setPrintAfter(false)
    setPrintData(null)
  }

  // Passo 1: escolher operação
  const handleEscolher = op => {
    setTipoOp(op)
    setStep(2)
  }

  // Passo 2: validar PIN
  const validarPin = () => {
    if (alunoPin.trim().length !== 4) {
      toast.warn('PIN deve ter 4 dígitos.', { autoClose: 5000 })
      return
    }
    axios.get(`/api/alunos/pin/${alunoPin}`)
      .then(res => {
        setAlunoNome(res.data.nome)
        setPinValidated(true)
        toast.success(`PIN validado: ${res.data.nome}`, { autoClose: 5000 })
        fetchHistory()
        setStep(3)
      })
      .catch(() => {
        toast.error('Aluno não encontrado por este PIN.', { autoClose: 5000 })
      })
  }

  // Passo 3: avançar após histórico
  const avancarParaSelecao = () => {
    setStep(4)
  }

  // Adiciona caixa selecionada (original)
  const addCaixa = c => {
    setCaixas(prev => [...prev, c])
    toast.success(`Caixa adicionada: ${c.nome}`, { autoClose: 5000 })
    setCodigo('')
  }

  const buscarCaixa = () => {
    const encontrada = allCaixas.find(c =>
      c.codigo_barras === codigo ||
      c.nome.toLowerCase().includes(codigo.toLowerCase())
    )
    if (!encontrada) {
      toast.error('Caixa não encontrada pelo código ou nome.', { autoClose: 5000 })
      return
    }
    addCaixa(encontrada)
  }

  const removerCaixa = id => {
    setCaixas(prev => {
      const idx = prev.findIndex(c => c.id === id)
      if (idx === -1) return prev
      const next = [...prev]; next.splice(idx, 1)
      return next
    })
  }

  // Botão confirmar (Passo 4)
  const confirmOperation = async () => {
    if (!pinValidated) {
      toast.warn('Valide o PIN antes.', { autoClose: 5000 })
      return
    }
    if (caixas.length === 0) {
      toast.warn('Adicione ao menos uma caixa.', { autoClose: 5000 })
      return
    }
    if (tipoOp === 'saida') {
      const invalid = caixas.filter(c => {
        const hist = historico.filter(m => m.caixa_id === c.id)
        return hist.length === 0 || hist[0].tipo !== 'entrada'
      })
      if (invalid.length) {
        invalid.forEach(c =>
          toast.error(`Não é possível dar saída da caixa "${c.nome}" sem entrada.`, { autoClose: 5000 })
        )
        return
      }
    }
    try {
      await Promise.all(caixas.map(c =>
        axios.post(`/api/movimentacoes/${tipoOp}`, {
          caixa_id: c.id,
          aluno_pin: alunoPin
        })
      ))
      toast.success(
        `${tipoOp === 'entrada' ? 'Entrada' : 'Saída'} registrada para ${alunoNome}!`,
        { autoClose: 5000 }
      )
      if (printAfter) {
        setStep(5)
      } else {
        resetWizard()
      }
    } catch {
      toast.error(`Erro ao registrar ${tipoOp}.`, { autoClose: 5000 })
    }
  }

  // Prepara printData
  const handlePrint = caixaEntry => {
    setPrintData({
      alunoNome,
      caixaId: caixaEntry.id,
      caixaNome: caixaEntry.nome,
      criadoEm: caixaEntry.criado_em || new Date().toISOString(),
      recebidoPor: usuarioLogadoNome,
    })
  }

  return (
    <div className="max-w-4xl mx-auto py-10 px-4 space-y-6">

      {/* Passo 1: Escolher Entrada ou Saída */}
      {step === 1 && (
        <div className="bg-white rounded-2xl shadow p-6 text-center space-y-4">
          <h2 className="text-2xl font-bold">Controle de Esterilização</h2>
          <button
            onClick={() => handleEscolher('entrada')}
            className="w-full py-2 bg-green-600 hover:bg-green-700 text-white rounded-full"
          >
            ENTRADA
          </button>
          <button
            onClick={() => handleEscolher('saida')}
            className="w-full py-2 bg-red-600 hover:bg-red-700 text-white rounded-full"
          >
            SAÍDA
          </button>
        </div>
      )}

      {/* Passo 2: Validar PIN */}
      {step === 2 && (
        <div className="bg-white rounded-2xl shadow p-6 space-y-4">
          <h3 className="text-xl font-semibold">Informe o PIN do aluno</h3>
          <input
            type="password"
            placeholder="PIN (4 dígitos)"
            value={alunoPin}
            onChange={e => setAlunoPin(e.target.value.replace(/\D/g, '').slice(0,4))}
            className="w-full border rounded px-3 py-2"
          />
          <button
            onClick={validarPin}
            className="w-full py-2 bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold rounded-full"
          >
            Avançar
          </button>
        </div>
      )}

      {/* Passo 3: Mostrar Nome, RA e Histórico */}
      {step === 3 && pinValidated && (
        <div className="bg-white rounded-2xl shadow p-6 space-y-4">
          <h3 className="text-lg font-semibold">Aluno: {alunoNome}</h3>
          <h4 className="font-medium">Histórico (últimos 30 dias)</h4>
          <ul className="list-disc ml-5 space-y-1 text-sm">
            {historico.map(m => (
              <li key={m.id}>
                {m.caixaNome} – {m.tipo} em {new Date(m.criado_em).toLocaleDateString()}
              </li>
            ))}
          </ul>
          <button
            onClick={avancarParaSelecao}
            className="w-full py-2 bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold rounded-full"
          >
            Avançar
          </button>
        </div>
      )}

      {/* Passo 4: Selecionar Caixas e Confirmar */}
      {step === 4 && (
        <>
          {/* busca de caixas */}
          <div className="bg-white rounded-2xl shadow p-6 space-y-4">
            <div className="relative flex flex-col md:flex-row gap-4">
              <input
                type="text"
                placeholder="Código ou nome da caixa"
                value={codigo}
                onChange={e => setCodigo(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), buscarCaixa())}
                className="flex-1 border rounded px-3 py-2"
              />
              <button
                onClick={buscarCaixa}
                className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold py-2 px-6 rounded-full"
              >
                Adicionar
              </button>
              {suggestions.length > 0 && (
                <ul className="absolute z-20 bg-white border rounded shadow mt-12 w-full md:w-auto max-h-40 overflow-y-auto">
                  {suggestions.map(c => (
                    <li
                      key={c.id}
                      className="px-3 py-2 hover:bg-gray-100 cursor-pointer"
                      onClick={() => addCaixa(c)}
                    >
                      {c.nome} ({c.codigo_barras})
                    </li>
                  ))}
                </ul>
              )}
            </div>
            {/* caixas selecionadas */}
            {uniqueCaixas.length > 0 && (
              <div className="flex flex-wrap gap-2">
                {uniqueCaixas.map(c => (
                  <div key={c.id} className="bg-gray-100 px-3 py-1 rounded-full flex items-center">
                    {c.nome} ({c.qty})
                    <button onClick={() => removerCaixa(c.id)} className="ml-2 text-gray-500">×</button>
                  </div>
                ))}
              </div>
            )}
            <label className="inline-flex items-center gap-2">
              <input
                type="checkbox"
                checked={printAfter}
                onChange={e => setPrintAfter(e.target.checked)}
              />
              <span>Imprimir etiquetas?</span>
            </label>
            <button
              onClick={confirmOperation}
              className="w-full py-2 bg-green-600 hover:bg-green-700 text-white rounded-full"
            >
              Confirmar {tipoOp.toUpperCase()}
            </button>
          </div>
        </>
      )}

      {/* Passo 5: Impressão de Etiquetas */}
      {step === 5 && (
        <div className="bg-white rounded-2xl shadow p-6 space-y-4">
          <h3 className="font-medium mb-2">Etiquetas para impressão</h3>
          <div className="flex flex-wrap gap-4">
            {uniqueCaixas.map(c => (
              <div key={c.id} className="flex items-center gap-2 bg-gray-50 p-2 rounded-full">
                <span className="font-medium">{c.nome}</span>
                <button
                  onClick={() => handlePrint(c)}
                  className="no-print"
                  title="Imprimir etiqueta desta caixa"
                >
                  <QrCode size={18} />
                </button>
              </div>
            ))}
          </div>
          <div className="flex gap-4">
            <button
              onClick={() => uniqueCaixas.forEach(c => handlePrint(c))}
              className="flex-1 py-2 bg-[#1A1C2C] hover:bg-[#3B4854] text-white rounded-full"
            >
              Imprimir todos
            </button>
            <button
              onClick={resetWizard}
              className="flex-1 py-2 bg-gray-300 text-black rounded-full"
            >
              Finalizar
            </button>
          </div>
        </div>
      )}

      {/* Área de Impressão (oculta) */}
      {printData && (
        <div id="area-impressao" style={{ position:'absolute', left:'-10000px', top:'-10000px' }}>
          <Etiqueta
            ref={componentRef}
            alunoNome={printData.alunoNome}
            caixaId={printData.caixaNome}
            criadoEm={printData.criadoEm}
            recebidoPor={printData.recebidoPor}
          />
        </div>
      )}

      {/* Estoque Atual (após confirmação) */}
      {pinValidated && Object.keys(stockByBox).length > 0 && step > 1 && step < 5 && (
        <div className="bg-white rounded-2xl shadow p-6">
          <h3 className="font-medium mb-2">Estoque Atual por Caixa</h3>
          <div className="flex flex-wrap gap-2">
            {Object.entries(stockByBox).map(([nome, qty], idx) => (
              <div
                key={nome}
                className={`px-3 py-1 rounded-full font-semibold ${BADGE_STYLES[idx % BADGE_STYLES.length]}`}
              >
                {nome}: {qty}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Histórico (sempre disponível) */}
      <div className="bg-white rounded-2xl shadow p-6">
        <h3 className="font-bold mb-4">Histórico (últimos 30 dias)</h3>
        <div className="flex flex-col md:flex-row justify-between gap-2 mb-4">
          <input
            type="text"
            placeholder="Pesquisar..."
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
            className="flex-1 border rounded px-3 py-2"
          />
          <button
            type="button"
            className="p-2 hover:bg-gray-100 rounded-full"
            onClick={() => datePickerRef.current.setOpen(true)}
          >
            <Calendar size={20} className="text-gray-600" />
          </button>
          <DatePicker
            ref={datePickerRef}
            selected={filterDate ? new Date(filterDate) : null}
            onChange={d => setFilterDate(d.toISOString().slice(0, 10))}
            customInput={<></>}
            locale="pt-BR"
            dateFormat="dd/MM/yyyy"
          />
        </div>
        <div className="hidden md:grid grid-cols-6 gap-4 text-sm font-semibold text-gray-600 border-b pb-2 mb-2">
          <div>Caixa</div><div>Tipo</div><div>Aluno</div><div>Operador</div><div>Data</div><div className="text-right">Ações</div>
        </div>
        {(() => {
          const fil = historico.filter(m => {
            const txt = searchTerm.toLowerCase()
            const okTxt = [m.caixaNome, m.tipo, m.alunoNome, m.operadorNome]
              .some(f => f.toLowerCase().includes(txt))
            const okDate = !filterDate || new Date(m.criado_em).toISOString().slice(0,10) === filterDate
            return okTxt && okDate
          })
          if (fil.length === 0) {
            return <p className="text-gray-500">Nenhuma movimentação.</p>
          }
          return (
            <div className="space-y-4">
              {fil.map(m => (
                <div key={m.id} className="grid grid-cols-1 md:grid-cols-6 gap-4 bg-gray-50 rounded-xl p-4 items-center">
                  <div className="font-medium">{m.caixaNome}</div>
                  <div>{m.tipo}</div>
                  <div>{m.alunoNome}</div>
                  <div>{m.operadorNome}</div>
                  <div>{new Date(m.criado_em).toLocaleString()}</div>
                  <div className="flex justify-end gap-4 items-center">
                    <button
                      onClick={() => handlePrint({ caixaId: m.caixa_id, caixaNome: m.caixaNome, criadoEm: m.criado_em, recebidoPor: usuarioLogadoNome, alunoNome })}
                      className="no-print cursor-pointer text-blue-600"
                      title="Reimprimir etiqueta"
                    >
                      <QrCode size={18} />
                    </button>
                    <Trash2
                      onClick={() => {
                        if (window.confirm('Deseja realmente excluir esta movimentação?'))
                          axios.delete(`/api/movimentacoes/${m.id}`)
                            .then(() => { setHistorico(h => h.filter(x => x.id !== m.id)); toast.success('Movimentação excluída.') })
                            .catch(() => toast.error('Erro ao excluir movimentação.'))
                      }}
                      className="cursor-pointer text-red-600"
                      size={18}
                      title="Excluir movimentação"
                    />
                  </div>
                </div>
              ))}
            </div>
          )
        })()}
      </div>

    </div>
  )
}
